setcpm(120/4)

// Each string is a mini-notation pattern.
// Space-separated values split the cycle evenly:
$: s("bd sd hh oh")

// * repeats inside the same step:
$: s("hh*8").gain(0.4)

// ~ is a rest (silence for one step):
$: s("bd ~ sd ~")

// [] groups values into a single step:
$: s("bd [hh hh] sd [hh oh]")

// <> alternates one value per cycle:
$: note("<c3 e3 g3 b3>").s("gm_electric_piano_1")

setcpm(120/4)

// s() triggers samples by name from the dirt-samples library:
$: s("bd sd cp hh")

// .bank() switches to a specific drum machine:
$: s("bd sd cp oh").bank("RolandTR909")

// Soundfonts are pitched — use with note():
$: note("c3 e3 g3 c4").s("gm_electric_piano_1")

// :N picks a sample variation (0-indexed):
$: s("hh:0 hh:1 hh:2 hh:3")

setcpm(100/4)

// .lpf() is a low-pass filter (cutoff in Hz):
$: s("sawtooth").note("c2 eb2 g2 bb2")
  .lpf(800).lpq(8)

// .room() adds reverb, .size() controls decay:
$: s("cp*2").room(0.8).size(0.9).gain(0.6)

// .delay() with .delaytime() and .delayfeedback():
$: note("c4 ~ e4 ~").s("gm_vibraphone")
  .delay(0.5).delaytime(0.375).delayfeedback(0.4)

// Envelope: .attack() .decay() .sustain() .release()
$: note("c3 e3 g3 b3").s("sawtooth")
  .attack(0.01).decay(0.2).sustain(0.3).release(0.5)
  .lpf(1200).gain(0.5)

setcpm(120/4)

// $: registers each layer independently (recommended):
$: s("bd*4").bank("RolandTR909").gain(0.9)
$: s("~ sd ~ sd").bank("RolandTR909")
$: s("hh*8").bank("RolandTR909").gain(0.4)

// stack() plays patterns simultaneously in one voice:
$: stack(
  note("c3 e3"),
  note("g3 b3"),
).s("gm_electric_piano_1").room(0.4)

// cat() sequences patterns across cycles:
$: cat(
  s("bd sd bd sd"),
  s("hh*8"),
)

setcpm(100/4)

// note() with letter names:
$: note("c3 e3 g3 b3").s("gm_electric_piano_1")

// .scale() constrains numbers to a scale:
$: n("0 2 4 6 3 5 7 4").scale("C4:minor")
  .s("gm_vibraphone").room(0.5)

// chord() for block chords:
$: chord("<Cm7 Fm7 Bbmaj7 Ebmaj7>")
  .s("gm_electric_piano_1")
  .voicing()
  .room(0.4)

// .add() transposes:
$: note("c3 e3 g3").add("<0 5 7 12>").s("triangle")

// setcpm(BPM / beats_per_cycle) sets the tempo:
setcpm(130/4)

// .fast() and .slow() change playback speed:
$: s("bd sd bd sd").bank("RolandTR909")
$: s("hh*4").fast(2).gain(0.4)

// .every(N, fn) applies a transformation every N cycles:
$: note("c3 e3 g3 b3").s("gm_vibraphone")
  .every(4, x => x.fast(2))
  .room(0.3)

// .sometimes() applies randomly (~50% of the time):
$: s("bd sd bd sd").sometimes(x => x.speed(1.5))

// .rev() reverses the pattern:
$: note("c3 d3 e3 f3 g3 a3 b3 c4").s("triangle")
  .every(2, rev)

setcpm(120/4)

// ? drops a hit 50% of the time:
$: s("hh hh? hh hh?").gain(0.5)

// .sometimes() applies a transform randomly:
$: s("bd sd bd sd")
  .sometimes(x => x.speed(2))

// randcat picks a random pattern each cycle:
$: randcat(
  s("bd sd bd sd"),
  s("bd bd sd sd"),
  s("bd*4"),
)

setcpm(100/4)

// .chop(N) slices a sample into N grains:
$: s("break:0").chop(16)

// .begin() and .end() play a portion (0–1):
$: s("break:1").begin(0.25).end(0.5).fast(2)

// .speed() changes playback rate:
$: s("bd").speed("<1 0.5 2 1.5>")

setcpm(120/4)

// 3 hits in 8 steps = tresillo rhythm:
$: s("bd(3,8)").gain(0.9)

// 5 in 8 = cinquillo:
$: s("rim(5,8)").gain(0.6)

// 7 in 16 = complex pattern:
$: s("hh(7,16)").gain(0.4)

// Combine for polyrhythmic texture:
$: note("c3(3,8)").s("gm_acoustic_bass")

